const H = {
  "Content-Type": "application/json",
  apikey: SUPABASE_KEY,
  Authorization: `Bearer ${SUPABASE_KEY}`,
  Prefer: "return=representation",
};
const Q = async (path, opts = {}) => {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    headers: H,
    ...opts,
  });
  if (!r.ok) {
    const e = await r.text();
    throw new Error(e);
  }
  const t = await r.text();
  return t ? JSON.parse(t) : [];
};
const sbGet = (t, q = "") => Q(`${t}?${q}`);
const sbPost = (t, b) => Q(t, { method: "POST", body: JSON.stringify(b) });
const sbPatch = (t, m, b) =>
  Q(`${t}?${m}`, { method: "PATCH", body: JSON.stringify(b) });
const sbDelete = (t, m) => Q(`${t}?${m}`, { method: "DELETE" });
const sbUpsert = (t, b, oc) =>
  Q(`${t}${oc ? `?on_conflict=${oc}` : ""}`, {
    method: "POST",
    headers: {
      ...H,
      Prefer: "resolution=merge-duplicates,return=representation",
    },
    body: JSON.stringify(b),
  });

