/* ── Auth ── */
async function hashPw(pw) {
  const b = await crypto.subtle.digest(
    "SHA-256",
    new TextEncoder().encode(pw + "esl_v7")
  );
  return Array.from(new Uint8Array(b))
    .map((x) => x.toString(16).padStart(2, "0"))
    .join("");
}

