const isInactiveStudent = (studentId, classes) => {
  const twoWeeksAgo = new Date();
  twoWeeksAgo.setDate(twoWeeksAgo.getDate() - 14);
  const cutoff = twoWeeksAgo.toISOString().split("T")[0];
  // Has any scheduled upcoming class?
  const hasUpcoming = classes.some(
    (c) =>
      c.studentId === studentId &&
      c.status === "scheduled" &&
      c.date >= todayStr()
  );
  if (hasUpcoming) return false;
  // Last completed or scheduled class
  const lastClass = classes
    .filter(
      (c) =>
        c.studentId === studentId &&
        (c.status === "completed" || c.status === "scheduled")
    )
    .sort((a, b) => b.date.localeCompare(a.date))[0];
  if (!lastClass) return false; // never booked — not "inactive", just new
  return lastClass.date < cutoff;
};
const getTeacherRating = (teacherId, classes) => {
  const rated = classes.filter(
    (c) => c.teacherId === teacherId && c.studentRating
  );
  if (!rated.length) return { avg: null, count: 0, reviews: [] };
  const ratings = rated.map((c) => c.studentRating);
  const reviews = rated
    .filter((c) => c.studentReview)
    .map((c) => ({
      classId: c.id,
      rating: c.studentRating,
      review: c.studentReview,
      studentId: c.studentId,
      date: c.date,
    }));
  return {
    avg:
      Math.round((ratings.reduce((a, b) => a + b, 0) / ratings.length) * 10) /
      10,
    count: ratings.length,
    reviews,
  };
};
const CLASS_RATE = { 25: 2.5, 40: 3.5, 55: 5 };
const calcSalary = (classes) =>
  classes.reduce((sum, c) => {
    const dur = c.duration || 55;
    const rate = CLASS_RATE[dur] || CLASS_RATE[55];
    return sum + rate;
  }, 0);
