/* ── Date helpers ── */
const addDays = (n, base) => {
  const d = base ? new Date(base + "T12:00:00") : new Date();
  d.setDate(d.getDate() + n);
  return d.toISOString().split("T")[0];
};
const dayOf = (ds) => {
  const i = new Date(ds + "T12:00:00").getDay();
  return DAYS[i === 0 ? 6 : i - 1];
};
const fmtDate = (ds) =>
  new Date(ds + "T12:00:00").toLocaleDateString("en-GB", {
    weekday: "short",
    day: "numeric",
    month: "short",
  });
const fmtDateLong = (ds) =>
  new Date(ds + "T12:00:00").toLocaleDateString("en-GB", {
    weekday: "long",
    day: "numeric",
    month: "long",
    year: "numeric",
  });
const endTime = (t, d) => {
  const [h, m] = t.split(":").map(Number),
    tot = h * 60 + m + d;
  const hh = Math.floor(tot / 60) % 24;
  return `${String(hh).padStart(2, "0")}:${String(tot % 60).padStart(2, "0")}`;
};
const toMs = (date, time) => new Date(date + "T" + time + ":00").getTime();
const classState = (date, time, dur) => {
  const now = Date.now(),
    s = toMs(date, time);
  const [h, m] = time.split(":").map(Number),
    tot = h * 60 + m + dur;
  // Handle midnight overflow
  const endDateStr = tot >= 1440 ? addDays(1, date) : date;
  const endT = `${String(Math.floor(tot / 60) % 24).padStart(2, "0")}:${String(
    tot % 60
  ).padStart(2, "0")}`;
  const e = toMs(endDateStr, endT);
  return now < s ? "upcoming" : now >= s && now < e ? "live" : "ended";
};
const msUntil = (date, time) => toMs(date, time) - Date.now();
const fmtCountdown = (ms) => {
  if (ms <= 0) return null;
  const s = Math.floor(ms / 1000),
    m = Math.floor(s / 60),
    h = Math.floor(m / 60),
    d = Math.floor(h / 24);
  if (d > 0) return `${d}d ${h % 24}h ${m % 60}m`;
  if (h > 0) return `${h}h ${m % 60}m ${s % 60}s`;
  if (m > 0) return `${m}m ${s % 60}s`;
  return `${s}s`;
};
const todayStr = () => new Date().toISOString().split("T")[0];

