function Avatar({ user, size = 40 }) {
  const c =
    user?.role === "teacher" || user?.role === "student"
      ? getTC(user?.id)
      : RMETA[user?.role]?.color || "#6B7280";
  const init = (user?.name || "?")
    .split(" ")
    .map((w) => w[0])
    .join("")
    .slice(0, 2);
  if (user?.avatarUrl)
    return (
      <img
        src={user.avatarUrl}
        alt={user.name}
        style={{
          width: size,
          height: size,
          borderRadius: "50%",
          objectFit: "cover",
          border: `2px solid ${c}33`,
          flexShrink: 0,
          transition: "transform .2s",
        }}
        onMouseEnter={(e) => (e.currentTarget.style.transform = "scale(1.08)")}
        onMouseLeave={(e) => (e.currentTarget.style.transform = "")}
      />
    );
  return (
    <div
      style={{
        width: size,
        height: size,
        borderRadius: "50%",
        background: c + "1A",
        border: `2px solid ${c}33`,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontSize: size * 0.34,
        fontWeight: 600,
        color: c,
        flexShrink: 0,
        transition: "transform .2s",
      }}
      onMouseEnter={(e) => (e.currentTarget.style.transform = "scale(1.08)")}
      onMouseLeave={(e) => (e.currentTarget.style.transform = "")}
    >
      {init}
    </div>
  );
}
