function useConfirm() {
  const [cfg, setCfg] = useState(null);
  const ask = (title, msg, variant = "danger") =>
    new Promise((r) => setCfg({ title, msg, variant, r }));
  const node = cfg ? (
    <ConfirmModal
      title={cfg.title}
      msg={cfg.msg}
      variant={cfg.variant}
      onYes={() => {
        cfg.r(true);
        setCfg(null);
      }}
      onNo={() => {
        cfg.r(false);
        setCfg(null);
      }}
    />
  ) : null;
  return [ask, node];
}
