/* ── Student Autocomplete Input ── */
function StudentPicker({
  value,
  onChange,
  students,
  placeholder = "Search student...",
}) {
  const [q, setQ] = useState("");
  const [open, setOpen] = useState(false);
  const ref = useRef();
  const selected = students.find((s) => s.id === value);
  const filtered = students
    .filter(
      (s) =>
        s.name.toLowerCase().includes(q.toLowerCase()) ||
        s.email.toLowerCase().includes(q.toLowerCase())
    )
    .slice(0, 8);
  useEffect(() => {
    const h = (e) => {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);
  return (
    <div ref={ref} style={{ position: "relative" }}>
      <div
        style={{
          ...baseInp,
          display: "flex",
          alignItems: "center",
          gap: 10,
          cursor: "text",
          padding: "10px 16px",
        }}
        onClick={() => {
          setOpen(true);
          setQ("");
        }}
      >
        {selected ? (
          <>
            <div style={{ flex: 1 }}>
              <span style={{ fontWeight: 600, color: "#1B2D6B" }}>
                {selected.name}
              </span>
              <span style={{ fontSize: 13, color: "#9CA3AF", marginLeft: 8 }}>
                {selected.email}
              </span>
            </div>
            <LvBadge level={selected.level} />
            <button
              onClick={(e) => {
                e.stopPropagation();
                onChange("");
                setQ("");
              }}
              style={{
                background: "none",
                border: "none",
                cursor: "pointer",
                color: "#9CA3AF",
                fontSize: 16,
                lineHeight: 1,
              }}
            >
              ✕
            </button>
          </>
        ) : (
          <input
            value={q}
            onChange={(e) => {
              setQ(e.target.value);
              setOpen(true);
            }}
            placeholder={placeholder}
            style={{
              border: "none",
              outline: "none",
              flex: 1,
              fontSize: 15,
              fontFamily: "Nunito",
              background: "transparent",
              color: "#1B2D6B",
            }}
            autoFocus={open}
          />
        )}
      </div>
      {open && !selected && (
        <div
          style={{
            position: "absolute",
            top: "100%",
            left: 0,
            right: 0,
            background: "#fff",
            borderRadius: 12,
            border: "1.5px solid #E5E7EB",
            boxShadow: "0 8px 24px rgba(0,0,0,.12)",
            zIndex: 200,
            overflow: "hidden",
            marginTop: 4,
          }}
        >
          {filtered.length === 0 ? (
            <div
              style={{ padding: "14px 16px", fontSize: 14, color: "#9CA3AF" }}
            >
              No students found
            </div>
          ) : (
            filtered.map((s) => (
              <button
                key={s.id}
                onClick={() => {
                  onChange(s.id);
                  setOpen(false);
                  setQ("");
                }}
                style={{
                  width: "100%",
                  display: "flex",
                  alignItems: "center",
                  gap: 12,
                  padding: "12px 16px",
                  border: "none",
                  background: "transparent",
                  cursor: "pointer",
                  textAlign: "left",
                  transition: "background .1s",
                }}
                onMouseEnter={(e) =>
                  (e.currentTarget.style.background = "#F9FAFB")
                }
                onMouseLeave={(e) =>
                  (e.currentTarget.style.background = "transparent")
                }
              >
                <div style={{ flex: 1 }}>
                  <div
                    style={{ fontWeight: 600, fontSize: 14, color: "#1B2D6B" }}
                  >
                    {s.name}
                  </div>
                  <div style={{ fontSize: 12, color: "#9CA3AF" }}>
                    {s.email} - {s.phone}
                  </div>
                </div>
                <LvBadge level={s.level} />
              </button>
            ))
          )}
        </div>
      )}
    </div>
  );
}

