/* ── Linkify text ── */
function Linkify({ text }) {
  if (!text) return null;
  const parts = text.split(/(https?:\/\/[^\s]+)/g);
  return (
    <>
      {parts.map((p, i) =>
        p.match(/^https?:\/\//) ? (
          <a
            key={i}
            href={p}
            target="_blank"
            rel="noopener noreferrer"
            style={{
              color: "#1B2D6B",
              fontWeight: 600,
              wordBreak: "break-all",
            }}
          >
            {p}
          </a>
        ) : (
          <span key={i}>{p}</span>
        )
      )}
    </>
  );
}

