/* ── Auto status updater ── */
function useAutoStatus(classes, onUpdate) {
  useEffect(() => {
    if (!classes.length) return;
    const check = async () => {
      const now = Date.now();
      const toComplete = classes.filter(
        (c) =>
          c.status === "scheduled" &&
          now >= toMs(c.date, endTime(c.time, c.duration || 55))
      );
      for (const c of toComplete) {
        try {
          await sbPatch("classes", `id=eq.${c.id}`, { status: "completed" });
        } catch (e) {}
      }
      if (toComplete.length) onUpdate();
    };
    check();
    const t = setInterval(check, 30000);
    return () => clearInterval(t);
  }, [classes]);
}

/* ── Availability Schedule View ── */
function AvailScheduleView({ teacher, avail }) {
  const [wk, setWk] = useState(0);
  const color = getTC(teacher.id);
  const start = new Date();
  start.setDate(
    start.getDate() - (start.getDay() === 0 ? 6 : start.getDay() - 1) + wk * 7
  );
  const wkDates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(start);
    d.setDate(start.getDate() + i);
    return d.toISOString().split("T")[0];
  });
  const todStr = todayStr();
  const wkLabel =
    wk === 0
      ? "This week"
      : wk === 1
      ? "Next week"
      : wk === -1
      ? "Last week"
      : `${wkDates[0].slice(5)} - ${wkDates[6].slice(5)}`;
  const slots = avail[teacher.id] || {};
  return (
    <div>
      <div
        style={{
          display: "flex",
          gap: 8,
          alignItems: "center",
          marginBottom: 16,
          flexWrap: "wrap",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 8,
            background: "#fff",
            borderRadius: 12,
            padding: "8px 14px",
            border: "1.5px solid #E5E7EB",
          }}
        >
          <button
            onClick={() => setWk((p) => p - 1)}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: 20,
              color: "#6B7280",
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = "#1B2D6B")}
            onMouseLeave={(e) => (e.currentTarget.style.color = "#6B7280")}
          >
            ‹
          </button>
          <span
            style={{
              fontSize: 13,
              fontWeight: 600,
              color: "#374151",
              minWidth: 90,
              textAlign: "center",
            }}
          >
            {wkLabel}
          </span>
          <button
            onClick={() => setWk((p) => p + 1)}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: 20,
              color: "#6B7280",
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = "#1B2D6B")}
            onMouseLeave={(e) => (e.currentTarget.style.color = "#6B7280")}
          >
            ›
          </button>
        </div>
        {wk !== 0 && (
          <Btn variant="ghost" size="sm" onClick={() => setWk(0)}>
            {"Today"}
          </Btn>
        )}
      </div>
      <div
        className="week-grid"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(7,1fr)",
          gap: 8,
        }}
      >
        {wkDates.map((date, di) => {
          const isToday = date === todStr,
            isPast = date < todStr;
          const d = new Date(date + "T12:00:00");
          const daySlots = slots[DAYS[di]] || [];
          return (
            <div key={date}>
              <div
                style={{
                  textAlign: "center",
                  padding: "8px 4px",
                  borderRadius: 12,
                  marginBottom: 8,
                  background: isToday ? "#1B2D6B" : "transparent",
                }}
              >
                <div
                  style={{
                    fontSize: 9,
                    fontWeight: 700,
                    textTransform: "uppercase",
                    color: isToday ? "#9CA3AF" : isPast ? "#D1D5DB" : "#9CA3AF",
                  }}
                >
                  {DAYS[di]}
                </div>
                <div
                  className="serif"
                  style={{
                    fontSize: 22,
                    lineHeight: 1.2,
                    marginTop: 2,
                    color: isToday ? "#fff" : isPast ? "#D1D5DB" : "#1B2D6B",
                  }}
                >
                  {d.getDate()}
                </div>
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                {daySlots.length === 0 ? (
                  <div
                    style={{
                      height: 32,
                      borderRadius: 8,
                      border: "1.5px dashed #E5E7EB",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                    }}
                  >
                    <span style={{ fontSize: 10, color: "#E5E7EB" }}>off</span>
                  </div>
                ) : (
                  daySlots.sort().map((slot) => (
                    <div
                      key={slot}
                      style={{
                        background: color + "18",
                        borderLeft: `3px solid ${color}`,
                        borderRadius: 8,
                        padding: "5px 8px",
                        fontSize: 11,
                        fontWeight: 700,
                        color,
                      }}
                    >
                      {slot}
                    </div>
                  ))
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function TeacherSchedulePicker({
  teacherId,
  date,
  avail,
  classes,
  adminMode,
  value,
  onChange,
  onDateChange,
}) {
  if (!teacherId) return null;
  const [wk, setWk] = useState(0);
  const start = new Date();
  start.setDate(
    start.getDate() - (start.getDay() === 0 ? 6 : start.getDay() - 1) + wk * 7
  );
  const wkDates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(start);
    d.setDate(start.getDate() + i);
    return d.toISOString().split("T")[0];
  });
  const todStr = todayStr();
  const wkLabel =
    wk === 0
      ? "This week"
      : wk === 1
      ? "Next week"
      : `${wkDates[0].slice(5)} - ${wkDates[6].slice(5)}`;
  const color = getTC(teacherId);
  return (
    <div>
      <div
        style={{
          display: "flex",
          gap: 8,
          alignItems: "center",
          marginBottom: 12,
          flexWrap: "wrap",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 6,
            background: "#F9FAFB",
            borderRadius: 10,
            padding: "6px 12px",
            border: "1.5px solid #E5E7EB",
          }}
        >
          <button
            onClick={() => setWk((p) => p - 1)}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: 18,
              color: "#6B7280",
              lineHeight: 1,
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = "#1B2D6B")}
            onMouseLeave={(e) => (e.currentTarget.style.color = "#6B7280")}
          >
            ‹
          </button>
          <span
            style={{
              fontSize: 13,
              fontWeight: 600,
              color: "#374151",
              minWidth: 90,
              textAlign: "center",
            }}
          >
            {wkLabel}
          </span>
          <button
            onClick={() => setWk((p) => p + 1)}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: 18,
              color: "#6B7280",
              lineHeight: 1,
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = "#1B2D6B")}
            onMouseLeave={(e) => (e.currentTarget.style.color = "#6B7280")}
          >
            ›
          </button>
        </div>
        {wk !== 0 && (
          <Btn variant="ghost" size="sm" onClick={() => setWk(0)}>
            {"Today"}
          </Btn>
        )}
      </div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(7,1fr)",
          gap: 6,
          overflowX: "auto",
        }}
      >
        {wkDates.map((d, di) => {
          const isToday = d === todStr,
            isPast = d < todStr;
          const daySlots = adminMode
            ? ALL_TIMES
            : avail[teacherId]?.[DAYS[di]] || [];
          const bookedSet = new Set(
            classes
              .filter(
                (c) =>
                  c.teacherId === teacherId &&
                  c.date === d &&
                  c.status === "scheduled"
              )
              .flatMap((c) =>
                needsTwoSlots(c.duration)
                  ? [c.time, nextSlot(c.time)]
                  : [c.time]
              )
          );
          const isSelDate = date === d;
          return (
            <div key={d}>
              <div
                style={{
                  textAlign: "center",
                  marginBottom: 6,
                  padding: "6px 4px",
                  borderRadius: 10,
                  background: isToday
                    ? "#1B2D6B"
                    : isSelDate
                    ? "#E8F5E9"
                    : "transparent",
                }}
              >
                <div
                  style={{
                    fontSize: 9,
                    fontWeight: 700,
                    textTransform: "uppercase",
                    color: isToday
                      ? "rgba(255,255,255,.6)"
                      : isPast
                      ? "#D1D5DB"
                      : "#9CA3AF",
                  }}
                >
                  {DAYS[di]}
                </div>
                <div
                  className="serif"
                  style={{
                    fontSize: 20,
                    lineHeight: 1.2,
                    marginTop: 2,
                    color: isToday ? "#fff" : isPast ? "#D1D5DB" : "#1B2D6B",
                  }}
                >
                  {new Date(d + "T12:00:00").getDate()}
                </div>
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 3 }}>
                {daySlots.length === 0 && !adminMode ? (
                  <div
                    style={{
                      height: 24,
                      borderRadius: 6,
                      background: "#F9FAFB",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                    }}
                  >
                    <span style={{ fontSize: 9, color: "#E5E7EB" }}>off</span>
                  </div>
                ) : (
                  daySlots.sort().map((slot) => {
                    const booked = bookedSet.has(slot);
                    const isSel = isSelDate && value === slot;
                    if (booked && !adminMode)
                      return (
                        <div
                          key={slot}
                          style={{
                            borderRadius: 6,
                            padding: "3px 5px",
                            background: "#FEF2F2",
                            border: "1.5px solid #FECACA",
                            fontSize: 10,
                            fontWeight: 600,
                            color: "#DC2626",
                            textAlign: "center",
                          }}
                        >
                          🔴 {slot}
                        </div>
                      );
                    return (
                      <button
                        key={slot}
                        onClick={() => {
                          if (!booked || adminMode) {
                            onDateChange(d);
                            onChange(slot);
                          }
                        }}
                        style={{
                          borderRadius: 6,
                          padding: "3px 5px",
                          background: isSel
                            ? "#1B2D6B"
                            : booked
                            ? "#F9FAFB"
                            : "#F0FDF4",
                          border: `1.5px solid ${
                            isSel
                              ? "#1B2D6B"
                              : booked
                              ? "#E5E7EB"
                              : color + "44"
                          }`,
                          fontSize: 10,
                          fontWeight: 700,
                          color: isSel ? "#fff" : booked ? "#D1D5DB" : color,
                          cursor:
                            booked && !adminMode ? "not-allowed" : "pointer",
                          transition: "all .12s",
                          fontFamily: "Nunito,sans-serif",
                        }}
                      >
                        {slot}
                      </button>
                    );
                  })
                )}
              </div>
            </div>
          );
        })}
      </div>
      {date && value && (
        <div
          style={{
            marginTop: 10,
            background: "#F0FDF4",
            borderRadius: 10,
            padding: "10px 14px",
            fontSize: 13,
            color: "#22C55E",
            fontWeight: 600,
          }}
        >
          {"✓ Selected:"} {fmtDate(date)} {"at"} {value}
        </div>
      )}
    </div>
  );
}

/* ── Assign/Edit Class Modal ── */
function AssignModal({
  staff,
  students,
  avail,
  holidays,
  classes,
  onAssign,
  onClose,
  adminMode = false,
  initialData = null,
}) {
  const [f, setF] = useState(
    initialData || {
      teacherId: ",studentId:",
      date: ",time:",
      level: "B1",
      duration: 55,
      classType: "Regular",
    }
  );
  // When student changes, update duration to their defaultDuration
  useEffect(() => {
    if (f.studentId) {
      const s = students.find((x) => x.id === f.studentId);
      if (s?.defaultDuration)
        setF((p) => ({ ...p, duration: s.defaultDuration }));
    }
  }, [f.studentId]);
  const [err, setErr] = useState("");
  const [saving, setSaving] = useState(false);
  const teachers = staff.filter((u) => u.role === "teacher");
  // When student selected, auto-fill level
  const onStudentChange = (sid) => {
    const s = students.find((x) => x.id === sid);
    setF((p) => ({ ...p, studentId: sid, level: s?.level || p.level }));
  };
  const getSlots = (tid, date) => {
    const teacherId = tid || f.teacherId;
    const d = date || f.date;
    if (!teacherId || !d) return ALL_TIMES;
    const day = dayOf(d),
      slots = avail[teacherId]?.[day] || [];
    return adminMode ? ALL_TIMES : slots.length ? slots : ALL_TIMES;
  };
  // Auto-set time to first available slot when teacher or date changes
  const onTeacherChange = (tid) => {
    const slots = getSlots(tid, f.date);
    setF((p) => ({ ...p, teacherId: tid, time: slots[0] || "09:00" }));
  };
  const onDateChange = (d) => {
    const slots = getSlots(f.teacherId, d);
    setF((p) => ({ ...p, date: d, time: slots[0] || "09:00" }));
  };
  const handle = async () => {
    setErr("");
    if (!f.teacherId || !f.studentId || !f.date) {
      setErr("Fill all required fields.");
      return;
    }
    const blocked = (holidays || []).some(
      (h) =>
        h.teacherId === f.teacherId &&
        h.status === "approved" &&
        f.date >= h.startDate &&
        f.date <= h.endDate
    );
    if (blocked) {
      setErr("Teacher is on approved holiday on this date.");
      return;
    }
    const resolvedTime = f.time || getSlots()[0] || "09:00";
    if (!adminMode) {
      const day = dayOf(f.date),
        slots = avail[f.teacherId]?.[day] || [];
      if (slots.length > 0 && !slots.includes(resolvedTime)) {
        setErr(`Not available at ${resolvedTime} on ${dayOf(f.date)}.`);
        return;
      }
    }
    // Check if teacher is free - 40/55min classes need two consecutive slots
    const slotsNeeded = needsTwoSlots(f.duration)
      ? [resolvedTime, nextSlot(resolvedTime)]
      : [resolvedTime];
    const conflict = (classes || []).find(
      (c) =>
        c.teacherId === f.teacherId &&
        c.date === f.date &&
        c.status === "scheduled" &&
        c.id !== initialData?.id &&
        (slotsNeeded.includes(c.time) ||
          (needsTwoSlots(c.duration) &&
            [c.time, nextSlot(c.time)].includes(resolvedTime)))
    );
    if (conflict) {
      setErr(
        `Teacher already has a class at that time (including buffer for ${conflict.duration}min classes).`
      );
      return;
    }
    const finalF = { ...f, time: resolvedTime };
    setSaving(true);
    try {
      await onAssign(finalF);
      onClose();
    } catch (e) {
      setErr("Failed to save.");
      setSaving(false);
    }
  };
  const slots = getSlots();
  // Ensure selected time is always valid
  const displayTime = slots.includes(f.time) ? f.time : slots[0] || "09:00";
  const selectedStudent = students.find((s) => s.id === f.studentId);
  return (
    <Modal
      title={initialData ? "Edit Class" : "Assign New Class"}
      onClose={onClose}
    >
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        <Field label="Teacher">
          <select
            value={f.teacherId}
            onChange={(e) => onTeacherChange(e.target.value)}
            style={baseInp}
          >
            <option value="">Select teacher...</option>
            {teachers.map((t) => (
              <option key={t.id} value={t.id}>
                {t.name}
              </option>
            ))}
          </select>
        </Field>
        <Field label="Student">
          <StudentPicker
            value={f.studentId}
            onChange={onStudentChange}
            students={students}
            placeholder="Search by name or email..."
          />
        </Field>
        {selectedStudent && (
          <div
            style={{
              background: "#F9FAFB",
              borderRadius: 12,
              padding: "12px 16px",
              display: "flex",
              gap: 12,
              alignItems: "center",
            }}
          >
            <LvBadge level={selectedStudent.level} large />
            <div style={{ fontSize: 14, color: "#374151" }}>
              {selectedStudent.notes || "No notes"}
            </div>
            <span
              style={{ marginLeft: "auto", fontSize: 13, color: "#9CA3AF" }}
            >
              {selectedStudent.phone}
            </span>
          </div>
        )}
        <Field label={"Pick a date and time"}>
          <TeacherSchedulePicker
            teacherId={f.teacherId}
            date={f.date}
            avail={avail}
            classes={classes}
            adminMode={adminMode}
            value={displayTime}
            onChange={(t) => setF((p) => ({ ...p, time: t }))}
            onDateChange={(d) => setF((p) => ({ ...p, date: d, time: "" }))}
          />
        </Field>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit,minmax(120px,1fr))",
            gap: 14,
          }}
        >
          {adminMode && (
            <Field label="Level">
              <select
                value={f.level}
                onChange={(e) => setF((p) => ({ ...p, level: e.target.value }))}
                style={baseInp}
              >
                {LEVELS.map((l) => (
                  <option key={l} value={l}>
                    {l}
                  </option>
                ))}
              </select>
            </Field>
          )}
          <Field label="Duration">
            <select
              value={f.duration}
              onChange={(e) =>
                setF((p) => ({ ...p, duration: +e.target.value }))
              }
              style={baseInp}
            >
              {DURS.map((d) => {
                const s = students.find((x) => x.id === f.studentId);
                const isDef = s?.defaultDuration === d;
                return (
                  <option key={d} value={d}>
                    {d} min{isDef ? " (student default)" : ""}
                  </option>
                );
              })}
            </select>
          </Field>
          <Field label="Class Type">
            <select
              value={f.classType || "Regular"}
              onChange={(e) =>
                setF((p) => ({ ...p, classType: e.target.value }))
              }
              style={baseInp}
            >
              <option value="Regular">Regular</option>
              <option value="Trial">Trial</option>
            </select>
          </Field>
        </div>
        {err && (
          <div
            style={{
              background: "#FEF2F2",
              border: "1px solid #FECACA",
              borderRadius: 10,
              padding: "12px 16px",
              fontSize: 14,
              color: "#DC2626",
            }}
          >
            {err}
          </div>
        )}
        <div style={{ display: "flex", gap: 12 }}>
          <Btn variant="ghost" onClick={onClose} fullWidth>
            {"Cancel"}
          </Btn>
          <Btn onClick={handle} fullWidth disabled={saving}>
            {saving ? "Saving..." : "Assign Class"}
          </Btn>
        </div>
      </div>
    </Modal>
  );
}

/* ── Move Class Between Teachers Modal ── */
function MoveTeacherModal({
  cls,
  staff,
  avail,
  holidays,
  classes,
  students,
  onMove,
  onClose,
}) {
  const [teacherId, setTeacherId] = useState("");
  const [err, setErr] = useState("");
  const [saving, setSaving] = useState(false);
  const student = students.find((s) => s.id === cls.studentId);
  const day = new Date(cls.date + "T12:00:00").toLocaleString("en", {
    weekday: "short",
  });
  const slotsNeeded = needsTwoSlots(cls.duration)
    ? [cls.time, nextSlot(cls.time)]
    : [cls.time];

  // Build list of eligible teachers with reason if unavailable
  const teacherOptions = staff
    .filter((u) => u.role === "teacher" && u.id !== cls.teacherId)
    .map((t) => {
      // Check availability — teacher must have ALL required slots open
      const teacherSlots = (avail[t.id] || {})[day] || [];
      const hasSlots = slotsNeeded.every((s) => teacherSlots.includes(s));
      if (!hasSlots)
        return { ...t, disabled: true, reason: "Not available at this time" };
      // Check holiday
      const onHoliday = (holidays || []).some(
        (h) =>
          h.teacherId === t.id &&
          h.status === "approved" &&
          cls.date >= h.startDate &&
          cls.date <= h.endDate
      );
      if (onHoliday) return { ...t, disabled: true, reason: "On holiday" };
      // Check class conflict
      const hasConflict = (classes || []).some(
        (c) =>
          c.teacherId === t.id &&
          c.date === cls.date &&
          c.status === "scheduled" &&
          c.id !== cls.id &&
          (slotsNeeded.includes(c.time) ||
            (needsTwoSlots(c.duration) &&
              [c.time, nextSlot(c.time)].some((s) => slotsNeeded.includes(s))))
      );
      if (hasConflict)
        return {
          ...t,
          disabled: true,
          reason: "Has another class at this time",
        };
      return { ...t, disabled: false, reason: "" };
    });

  const available = teacherOptions.filter((t) => !t.disabled);
  const unavailable = teacherOptions.filter((t) => t.disabled);

  const handle = async () => {
    if (!teacherId) {
      setErr("Select a teacher.");
      return;
    }
    setSaving(true);
    try {
      await onMove(cls.id, teacherId);
      onClose();
    } catch (e) {
      setErr("Failed to move class.");
      setSaving(false);
    }
  };

  return (
    <Modal
      title="Move to Different Teacher"
      subtitle={`${student?.name} - ${fmtDate(cls.date)} at ${cls.time}`}
      onClose={onClose}
    >
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        {err && (
          <div
            style={{
              background: "#FEF2F2",
              border: "1px solid #FECACA",
              borderRadius: 10,
              padding: "12px 16px",
              fontSize: 14,
              color: "#DC2626",
            }}
          >
            {err}
          </div>
        )}

        {/* Available teachers */}
        {available.length > 0 && (
          <div>
            <div
              style={{
                fontSize: 12,
                fontWeight: 700,
                color: "#15803D",
                textTransform: "uppercase",
                letterSpacing: ".06em",
                marginBottom: 8,
              }}
            >
              ✅ Available ({available.length})
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {available.map((t) => (
                <button
                  key={t.id}
                  onClick={() => setTeacherId(t.id)}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 12,
                    padding: "10px 14px",
                    borderRadius: 10,
                    border: `2px solid ${
                      teacherId === t.id ? "#22C55E" : "#E5E7EB"
                    }`,
                    background: teacherId === t.id ? "#F0FDF4" : "#fff",
                    cursor: "pointer",
                    textAlign: "left",
                    transition: "all .15s",
                  }}
                >
                  <Avatar user={t} size={36} />
                  <div style={{ flex: 1 }}>
                    <div
                      style={{
                        fontWeight: 700,
                        fontSize: 14,
                        color: "#1B2D6B",
                      }}
                    >
                      {t.name}
                    </div>
                    <div
                      style={{
                        fontSize: 11,
                        color: "#22C55E",
                        fontWeight: 600,
                      }}
                    >
                      Available at {cls.time}
                    </div>
                  </div>
                  {teacherId === t.id && (
                    <span style={{ color: "#22C55E", fontSize: 18 }}>✓</span>
                  )}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Unavailable teachers */}
        {unavailable.length > 0 && (
          <div>
            <div
              style={{
                fontSize: 12,
                fontWeight: 700,
                color: "#9CA3AF",
                textTransform: "uppercase",
                letterSpacing: ".06em",
                marginBottom: 8,
              }}
            >
              ❌ Unavailable ({unavailable.length})
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {unavailable.map((t) => (
                <div
                  key={t.id}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 12,
                    padding: "10px 14px",
                    borderRadius: 10,
                    border: "2px solid #F3F4F6",
                    background: "#F9FAFB",
                    opacity: 0.7,
                  }}
                >
                  <Avatar user={t} size={36} />
                  <div style={{ flex: 1 }}>
                    <div
                      style={{
                        fontWeight: 700,
                        fontSize: 14,
                        color: "#9CA3AF",
                      }}
                    >
                      {t.name}
                    </div>
                    <div
                      style={{
                        fontSize: 11,
                        color: "#EF4444",
                        fontWeight: 600,
                      }}
                    >
                      {t.reason}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {available.length === 0 && (
          <div
            style={{
              background: "#FEF2F2",
              borderRadius: 10,
              padding: 16,
              textAlign: "center",
              color: "#DC2626",
              fontSize: 14,
            }}
          >
            No teachers are available at this time slot.
          </div>
        )}

        <div style={{ display: "flex", gap: 12 }}>
          <Btn variant="ghost" onClick={onClose} fullWidth>
            Cancel
          </Btn>
          <Btn
            onClick={handle}
            fullWidth
            disabled={saving || !teacherId || available.length === 0}
          >
            {saving ? "Moving..." : "Move Class"}
          </Btn>
        </div>
      </div>
    </Modal>
  );
}

/* ── Feedback & HW Composers ── */
function FeedbackComposer({
  classId,
  studentId,
  teacherId,
  student,
  existing,
  onSend,
  onClose,
}) {
  const [att, setAtt] = useState(existing?.attendance || "");
  const [score, setScore] = useState(existing?.score ?? null);
  const [fb, setFb] = useState(
    existing?.feedback || {
      grammar: "",
      pronunciation: "",
      vocabulary: "",
      todayLesson: "",
      nextLesson: "",
      comments: "",
    }
  );
  const [saving, setSaving] = useState(false);
  const send = async () => {
    setSaving(true);
    try {
      await onSend({
        id: existing?.id,
        classId,
        studentId,
        teacherId,
        type: "feedback",
        attendance: att,
        score,
        feedback: fb,
        date: new Date().toISOString().split("T")[0],
      });
      onClose();
    } catch (e) {
      setSaving(false);
    }
  };
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <div style={{ background: "#F9FAFB", borderRadius: 12, padding: 16 }}>
        <div
          style={{
            fontSize: 13,
            fontWeight: 700,
            color: "#6B7280",
            marginBottom: 10,
            textTransform: "uppercase",
            letterSpacing: ".05em",
          }}
        >
          Attendance
        </div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          {["present", "absent", "late"].map((s) => {
            const a = att === s,
              c = { present: "#22C55E", absent: "#DC2626", late: "#D97706" }[s];
            return (
              <button
                key={s}
                onClick={() => setAtt(s)}
                style={{
                  padding: "9px 22px",
                  borderRadius: 10,
                  border: `2px solid ${a ? c : "#E5E7EB"}`,
                  background: a ? c + "18" : "#fff",
                  color: a ? c : "#9CA3AF",
                  fontSize: 14,
                  fontWeight: 700,
                  cursor: "pointer",
                  textTransform: "capitalize",
                  transition: "all .15s",
                }}
              >
                {s}
              </button>
            );
          })}
        </div>
      </div>
      <div style={{ background: "#F9FAFB", borderRadius: 12, padding: 16 }}>
        <div
          style={{
            fontSize: 13,
            fontWeight: 700,
            color: "#6B7280",
            marginBottom: 12,
            textTransform: "uppercase",
            letterSpacing: ".05em",
          }}
        >
          Score out of 20
        </div>
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
          {Array.from({ length: 21 }, (_, i) => i).map((n) => (
            <button
              key={n}
              onClick={() => setScore(n)}
              style={{
                width: "calc(9% - 4px)",
                minWidth: 34,
                height: 38,
                borderRadius: 9,
                border: `2px solid ${score === n ? "#1B2D6B" : "#E5E7EB"}`,
                background: score === n ? "#1B2D6B" : "#fff",
                color: score === n ? "#fff" : "#374151",
                fontWeight: 700,
                fontSize: 13,
                cursor: "pointer",
                transition: "all .15s",
              }}
            >
              {n}
            </button>
          ))}
        </div>
        {score != null && (
          <div style={{ marginTop: 10, fontSize: 14, color: "#6B7280" }}>
            Score: <b style={{ color: "#1B2D6B" }}>{score}/20</b> -{" "}
            {score >= 16
              ? "Excellent 🌟"
              : score >= 12
              ? "Good 👍"
              : score >= 8
              ? "Fair ⚡"
              : "Needs work 💪"}
          </div>
        )}
      </div>
      {FB_FIELDS.map((f, fi) => (
        <div
          key={f.key}
          className={`fade-up-${Math.min(fi + 2, 5)}`}
          style={{
            borderRadius: 12,
            border: `1.5px solid ${f.color}22`,
            overflow: "hidden",
          }}
        >
          <div style={{ background: f.color, padding: "9px 16px" }}>
            <span style={{ fontSize: 13, fontWeight: 700, color: "#fff" }}>
              {f.label}
            </span>
          </div>
          <textarea
            value={fb[f.key]}
            onChange={(e) => setFb((p) => ({ ...p, [f.key]: e.target.value }))}
            rows={2}
            placeholder={`Notes on ${f.label.toLowerCase()}...`}
            style={{
              ...baseInp,
              borderRadius: 0,
              border: "none",
              fontSize: 14,
              resize: "vertical",
              background: "#fff",
            }}
          />
        </div>
      ))}
      <div style={{ display: "flex", gap: 12 }}>
        <Btn variant="ghost" onClick={onClose} fullWidth>
          {"Cancel"}
        </Btn>
        <button
          onClick={send}
          disabled={saving}
          style={{
            flex: 1,
            padding: "13px 0",
            borderRadius: 12,
            border: "none",
            background: "#25D366",
            color: "#fff",
            fontWeight: 700,
            fontSize: 15,
            cursor: "pointer",
            opacity: saving ? 0.6 : 1,
          }}
          onMouseEnter={(e) =>
            (e.currentTarget.style.filter = "brightness(.9)")
          }
          onMouseLeave={(e) => (e.currentTarget.style.filter = "")}
        >
          {saving ? "Saving..." : "📲 Send Feedback"}
        </button>
      </div>
    </div>
  );
}
