/* ── Week Schedule Grid ── */
function WeekSchedule({
  classes,
  staff,
  students,
  avail,
  holidays = [],
  filterTeacherId,
  onCancel,
  onReschedule,
  onMoveTeacher,
  readOnly = false,
  canMoveTeacher = false,
}) {
  const [tFilter, setTFilter] = useState(filterTeacherId || "all");
  const [sFilter, setSFilter] = useState("scheduled");
  const [wk, setWk] = useState(0);
  const [rsTarget, setRsTarget] = useState(null);
  const [mtTarget, setMtTarget] = useState(null);
  const [rsForm, setRsForm] = useState({ date: "", time: "09:00" });
  const [rsErr, setRsErr] = useState("");
  const [ask, confirmNode] = useConfirm();
  const teachers = staff.filter((u) => u.role === "teacher");
  const gS = (id) => students.find((s) => s.id === id);
  const gU = (id) => staff.find((u) => u.id === id);
  const todStr = todayStr();
  const start = new Date();
  start.setDate(
    start.getDate() - (start.getDay() === 0 ? 6 : start.getDay() - 1) + wk * 7
  );
  const wkDates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(start);
    d.setDate(start.getDate() + i);
    return d.toISOString().split("T")[0];
  });
  const filtered = classes.filter((c) => {
    if (sFilter !== "all" && c.status !== sFilter) return false;
    if (tFilter !== "all" && c.teacherId !== tFilter) return false;
    if (filterTeacherId && c.teacherId !== filterTeacherId) return false;
    return wkDates.includes(c.date);
  });
  const byDate = wkDates.reduce((a, d) => {
    a[d] = filtered
      .filter((c) => c.date === d)
      .sort((a, b) => a.time.localeCompare(b.time));
    return a;
  }, {});
  const wkLabel =
    wk === 0
      ? "This week"
      : wk === 1
      ? "Next week"
      : wk === -1
      ? "Last week"
      : `${wkDates[0].slice(5)} - ${wkDates[6].slice(5)}`;
  const doCancel = async (c) => {
    const ok = await ask(
      "Cancel Class",
      `Cancel ${gS(c.studentId)?.name}'s class on ${fmtDate(c.date)} at ${
        c.time
      }?`
    );
    if (ok) onCancel(c.id);
  };
  const openRs = (c) => {
    setRsTarget(c);
    setRsForm({ date: c.date, time: c.time });
    setRsErr("");
  };
  const doRs = () => {
    setRsErr("");
    if (!rsForm.date || !rsForm.time) {
      setRsErr("Fill date and time.");
      return;
    }
    const day = dayOf(rsForm.date);
    if (!readOnly) {
      const slots = avail[rsTarget.teacherId]?.[day] || [];
      if (slots.length > 0 && !slots.includes(rsForm.time)) {
        setRsErr(
          `Teacher not available at ${
            rsForm.time
          } on ${day}. Available: ${slots.join(", ")}`
        );
        return;
      }
    }
    const rsSlotsNeeded = needsTwoSlots(rsTarget.duration)
      ? [rsForm.time, nextSlot(rsForm.time)]
      : [rsForm.time];
    const conflict = classes.find(
      (c) =>
        c.id !== rsTarget.id &&
        c.teacherId === rsTarget.teacherId &&
        c.date === rsForm.date &&
        c.status === "scheduled" &&
        (rsSlotsNeeded.includes(c.time) ||
          (needsTwoSlots(c.duration) &&
            [c.time, nextSlot(c.time)].includes(rsForm.time)))
    );
    if (conflict) {
      setRsErr(
        `${
          gU(rsTarget.teacherId)?.name?.split(" ")[0]
        } already has a class at that time.`
      );
      return;
    }
    onReschedule(rsTarget.id, { date: rsForm.date, time: rsForm.time, day });
    setRsTarget(null);
  };
  const [selDay, setSelDay] = useState(null);
  const [selTeacher, setSelTeacher] = useState(""); // null = show all days on desktop
  const todayIdx = new Date().getDay();
  return (
    <div>
      {confirmNode}
      <div
        style={{
          display: "flex",
          gap: 10,
          alignItems: "center",
          flexWrap: "wrap",
          marginBottom: 16,
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 8,
            background: "#fff",
            borderRadius: 12,
            padding: "8px 14px",
            border: "1.5px solid #E5E7EB",
          }}
        >
          <button
            onClick={() => setWk((p) => p - 1)}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: 20,
              color: "#6B7280",
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = "#1B2D6B")}
            onMouseLeave={(e) => (e.currentTarget.style.color = "#6B7280")}
          >
            ‹
          </button>
          <span
            style={{
              fontSize: 14,
              fontWeight: 600,
              color: "#374151",
              minWidth: 100,
              textAlign: "center",
            }}
          >
            {wkLabel}
          </span>
          <button
            onClick={() => setWk((p) => p + 1)}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: 20,
              color: "#6B7280",
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = "#1B2D6B")}
            onMouseLeave={(e) => (e.currentTarget.style.color = "#6B7280")}
          >
            ›
          </button>
        </div>
        {wk !== 0 && (
          <Btn variant="ghost" size="sm" onClick={() => setWk(0)}>
            {"Today"}
          </Btn>
        )}
        {!filterTeacherId && (
          <select
            value={tFilter}
            onChange={(e) => setTFilter(e.target.value)}
            style={{
              ...baseInp,
              width: "auto",
              padding: "9px 14px",
              fontSize: 14,
            }}
            className="hide-mobile"
          >
            <option value="all">All Teachers</option>
            {teachers.map((t) => (
              <option key={t.id} value={t.id}>
                {t.name}
              </option>
            ))}
          </select>
        )}
        <select
          value={sFilter}
          onChange={(e) => setSFilter(e.target.value)}
          style={{
            ...baseInp,
            width: "auto",
            padding: "9px 14px",
            fontSize: 14,
          }}
        >
          <option value="all">All</option>
          <option value="scheduled">Scheduled</option>
          <option value="completed">Completed</option>
          <option value="cancelled">Cancelled</option>
        </select>
        <span style={{ marginLeft: "auto", fontSize: 14, color: "#6B7280" }}>
          <b style={{ color: "#1B2D6B" }}>
            {filtered.filter((c) => c.status === "scheduled").length}
          </b>{" "}
          scheduled
        </span>
      </div>
      {/* Day selector pills for mobile */}
      <div
        style={{
          display: "flex",
          gap: 6,
          marginBottom: 14,
          overflowX: "auto",
          paddingBottom: 4,
        }}
      >
        <select
          value={selTeacher}
          onChange={(e) => setSelTeacher(e.target.value)}
          style={{
            ...baseInp,
            width: "auto",
            minWidth: 150,
            fontSize: 12,
            flexShrink: 0,
          }}
        >
          <option value="">All teachers</option>
          {staff
            .filter((u) => u.role === "teacher")
            .map((t) => (
              <option key={t.id} value={t.id}>
                {t.name}
              </option>
            ))}
        </select>
        <button
          onClick={() => setSelDay(null)}
          style={{
            padding: "6px 14px",
            borderRadius: 99,
            border: "none",
            background: selDay === null ? "#1B2D6B" : "#F3F4F6",
            color: selDay === null ? "#fff" : "#6B7280",
            fontWeight: 600,
            fontSize: 12,
            cursor: "pointer",
            whiteSpace: "nowrap",
            fontFamily: "Nunito",
            flexShrink: 0,
          }}
        >
          All days
        </button>
        {wkDates.map((date, di) => {
          const isToday = date === todStr,
            cnt = (
              selTeacher
                ? (byDate[date] || []).filter((c) => c.teacherId === selTeacher)
                : byDate[date] || []
            ).length;
          return (
            <button
              key={date}
              onClick={() => setSelDay(selDay === date ? null : date)}
              style={{
                padding: "6px 14px",
                borderRadius: 99,
                border: "none",
                background:
                  selDay === date ? "#1B2D6B" : isToday ? "#F3F4F6" : "#F9FAFB",
                color:
                  selDay === date ? "#fff" : isToday ? "#1B2D6B" : "#6B7280",
                fontWeight: isToday ? 700 : 500,
                fontSize: 12,
                cursor: "pointer",
                whiteSpace: "nowrap",
                fontFamily: "Nunito",
                flexShrink: 0,
              }}
            >
              {DAYS[di]} {cnt > 0 ? `(${cnt})` : ""}
            </button>
          );
        })}
      </div>
      <div
        className="week-grid"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(7,1fr)",
          gap: 10,
        }}
      >
        {wkDates
          .filter((date) => !selDay || date === selDay)
          .map((date, _di) => {
            const dayClasses = (byDate[date] || []).filter(
              (c) => !selTeacher || c.teacherId === selTeacher
            );
            const di = wkDates.indexOf(date);
            const isToday = date === todStr,
              isPast = date < todStr;
            const d = new Date(date + "T12:00:00");
            return (
              <div key={date}>
                <div
                  style={{
                    textAlign: "center",
                    padding: "10px 6px",
                    borderRadius: 14,
                    marginBottom: 10,
                    background: isToday ? "#1B2D6B" : "transparent",
                  }}
                >
                  <div
                    style={{
                      fontSize: 9,
                      fontWeight: 700,
                      textTransform: "uppercase",
                      color: isToday
                        ? "#9CA3AF"
                        : isPast
                        ? "#D1D5DB"
                        : "#9CA3AF",
                    }}
                  >
                    {DAYS[di]}
                  </div>
                  <div
                    className="serif"
                    style={{
                      fontSize: 24,
                      lineHeight: 1.2,
                      marginTop: 3,
                      color: isToday ? "#fff" : isPast ? "#D1D5DB" : "#1B2D6B",
                    }}
                  >
                    {d.getDate()}
                  </div>
                  <div
                    style={{
                      fontSize: 10,
                      color: isToday
                        ? "rgba(255,255,255,.4)"
                        : isPast
                        ? "#E5E7EB"
                        : "#D1D5DB",
                      marginTop: 1,
                    }}
                  >
                    {d.toLocaleString("default", { month: "short" })}
                  </div>
                </div>
                <div
                  style={{ display: "flex", flexDirection: "column", gap: 6 }}
                >
                  {byDate[date].length === 0 && (
                    <div
                      style={{
                        height: 48,
                        borderRadius: 12,
                        border: "1.5px dashed #E5E7EB",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                      }}
                    >
                      <span style={{ fontSize: 11, color: "#E5E7EB" }}>-</span>
                    </div>
                  )}
                  {byDate[date].map((c) => {
                    const tc = getTC(c.teacherId),
                      isCan = c.status === "cancelled",
                      isDone = c.status === "completed";
                    const cs =
                      !isCan && !isDone
                        ? classState(c.date, c.time, c.duration || 55)
                        : "";
                    return (
                      <div
                        key={c.id}
                        style={{
                          background: isCan
                            ? "#FEF2F2"
                            : isDone
                            ? "#F0FDF4"
                            : cs === "live"
                            ? "#FFFBEB"
                            : tc + "14",
                          border: `1.5px solid ${
                            isCan
                              ? "#FECACA"
                              : isDone
                              ? "#86EFAC"
                              : cs === "live"
                              ? "#FDE68A"
                              : tc + "35"
                          }`,
                          borderLeft: `4px solid ${
                            isCan
                              ? "#EF4444"
                              : isDone
                              ? "#22C55E"
                              : cs === "live"
                              ? "#EAB308"
                              : tc
                          }`,
                          borderRadius: 12,
                          padding: "10px 11px",
                          opacity: isCan ? 0.65 : 1,
                        }}
                      >
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                            marginBottom: 4,
                          }}
                        >
                          <span style={{ fontSize: 13, fontWeight: 700 }}>
                            {c.time}
                          </span>
                          <LvBadge level={c.level} />
                        </div>
                        <div
                          style={{
                            fontSize: 12,
                            fontWeight: 600,
                            color: "#374151",
                            overflow: "hidden",
                            textOverflow: "ellipsis",
                            whiteSpace: "nowrap",
                            marginBottom: 3,
                          }}
                        >
                          {students.find((s) => s.id === c.studentId)?.name ||
                            "-"}
                        </div>
                        {!filterTeacherId && (
                          <div
                            style={{
                              fontSize: 11,
                              color: tc,
                              fontWeight: 600,
                              marginBottom: 3,
                            }}
                          >
                            {gU(c.teacherId)?.name?.split(" ")[0]}
                          </div>
                        )}
                        <div
                          style={{
                            display: "flex",
                            gap: 3,
                            alignItems: "center",
                            marginBottom: 3,
                          }}
                        >
                          <TBadge type={c.classType || "Regular"} />
                          <span
                            style={{
                              fontSize: 10,
                              color: "#9CA3AF",
                              fontWeight: 600,
                            }}
                          >
                            {c.duration || 55}m
                            {needsTwoSlots(c.duration || 55)
                              ? " (2 slots)"
                              : ""}
                          </span>
                        </div>
                        {cs === "live" && (
                          <div
                            style={{
                              fontSize: 10,
                              fontWeight: 700,
                              color: "#D97706",
                              marginTop: 2,
                            }}
                          >
                            🔴 LIVE
                          </div>
                        )}
                        {isCan && (
                          <div
                            style={{
                              fontSize: 10,
                              color: "#EF4444",
                              fontWeight: 700,
                              marginTop: 2,
                            }}
                          >
                            CANCELLED
                          </div>
                        )}
                        {isDone && (
                          <div
                            style={{
                              fontSize: 10,
                              color: "#22C55E",
                              fontWeight: 700,
                              marginTop: 2,
                            }}
                          >
                            DONE ✓
                          </div>
                        )}
                        {!readOnly && !isCan && !isDone && (
                          <div
                            style={{
                              display: "flex",
                              flexDirection: "column",
                              gap: 3,
                              marginTop: 7,
                            }}
                          >
                            <div style={{ display: "flex", gap: 3 }}>
                              <button
                                onClick={() => openRs(c)}
                                style={{
                                  flex: 1,
                                  padding: "4px 0",
                                  borderRadius: 7,
                                  border: "1.5px solid #E5E7EB",
                                  background: "#fff",
                                  fontSize: 10,
                                  fontWeight: 600,
                                  cursor: "pointer",
                                  color: "#6B7280",
                                }}
                                onMouseEnter={(e) =>
                                  (e.currentTarget.style.borderColor =
                                    "#9CA3AF")
                                }
                                onMouseLeave={(e) =>
                                  (e.currentTarget.style.borderColor =
                                    "#E5E7EB")
                                }
                              >
                                {"Reschedule"}
                              </button>
                              <button
                                onClick={() => doCancel(c)}
                                style={{
                                  flex: 1,
                                  padding: "4px 0",
                                  borderRadius: 7,
                                  border: "1.5px solid #FECACA",
                                  background: "#fff",
                                  fontSize: 10,
                                  fontWeight: 600,
                                  cursor: "pointer",
                                  color: "#EF4444",
                                }}
                                onMouseEnter={(e) =>
                                  (e.currentTarget.style.background = "#FEF2F2")
                                }
                                onMouseLeave={(e) =>
                                  (e.currentTarget.style.background = "#fff")
                                }
                              >
                                {"Cancel"}
                              </button>
                            </div>
                            {canMoveTeacher && (
                              <button
                                onClick={() => setMtTarget(c)}
                                style={{
                                  width: "100%",
                                  padding: "4px 0",
                                  borderRadius: 7,
                                  border: "1.5px solid #86EFAC",
                                  background: "#F0FDF4",
                                  fontSize: 10,
                                  fontWeight: 600,
                                  cursor: "pointer",
                                  color: "#1B2D6B",
                                }}
                                onMouseEnter={(e) =>
                                  (e.currentTarget.style.background = "#DCFCE7")
                                }
                                onMouseLeave={(e) =>
                                  (e.currentTarget.style.background = "#F0FDF4")
                                }
                              >
                                Move Teacher
                              </button>
                            )}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
      </div>
      {rsTarget && (
        <Modal
          title="Reschedule Class"
          subtitle={`${gS(rsTarget.studentId)?.name} - currently ${
            rsTarget.date
          } at ${rsTarget.time}`}
          onClose={() => setRsTarget(null)}
          width={620}
        >
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <div
              style={{
                background: "#F9FAFB",
                borderRadius: 10,
                padding: "10px 14px",
                fontSize: 13,
                color: "#6B7280",
              }}
            >
              Pick a new date and time from the teacher's availability below.
            </div>
            <TeacherSchedulePicker
              teacherId={rsTarget.teacherId}
              date={rsForm.date}
              avail={avail}
              classes={classes}
              adminMode={readOnly}
              value={rsForm.time}
              onChange={(t) => setRsForm((p) => ({ ...p, time: t }))}
              onDateChange={(d) =>
                setRsForm((p) => ({ ...p, date: d, time: "" }))
              }
            />
            {rsErr && (
              <div
                style={{
                  background: "#FEF2F2",
                  border: "1px solid #FECACA",
                  borderRadius: 10,
                  padding: "12px 16px",
                  fontSize: 14,
                  color: "#DC2626",
                }}
              >
                {rsErr}
              </div>
            )}
            <div style={{ display: "flex", gap: 12 }}>
              <Btn variant="ghost" onClick={() => setRsTarget(null)} fullWidth>
                Cancel
              </Btn>
              <Btn
                onClick={doRs}
                fullWidth
                disabled={!rsForm.date || !rsForm.time}
              >
                Save Changes
              </Btn>
            </div>
          </div>
        </Modal>
      )}
      {mtTarget && (
        <MoveTeacherModal
          cls={mtTarget}
          staff={staff}
          avail={avail}
          holidays={holidays}
          classes={classes}
          students={students}
          onMove={onMoveTeacher}
          onClose={() => setMtTarget(null)}
        />
      )}
    </div>
  );
}

/* ── Availability Grid (editable or read-only) ── */
function AvailGrid({
  teacher,
  avail,
  onSave,
  readOnly = false,
  showScheduleView = false,
  editMode = false,
  externalSlots = null,
  onChange = null,
}) {
  const [mode, setMode] = useState(showScheduleView ? "schedule" : "grid");
  const [editing, setEditing] = useState(false);
  const [ea, setEa] = useState(() =>
    JSON.parse(JSON.stringify(avail[teacher?.id] || {}))
  );
  const [saving, setSaving] = useState(false);
  useEffect(() => {
    if (!editMode) setEa(JSON.parse(JSON.stringify(avail[teacher?.id] || {})));
  }, [avail, teacher?.id]);
  const color = getTC(teacher.id);
  const openEdit = () => {
    setEa(JSON.parse(JSON.stringify(avail[teacher.id] || {})));
    setEditing(true);
  };
  const toggle = (day, h) => {
    if (editMode && onChange) {
      onChange(day, h);
      return;
    }
    setEa((p) => {
      const cur = p[day] || [];
      return {
        ...p,
        [day]: cur.includes(h) ? cur.filter((x) => x !== h) : [...cur, h],
      };
    });
  };
  const save = async () => {
    if (!onSave) return;
    setSaving(true);
    try {
      await onSave(teacher.id, ea);
      setEditing(false);
    } finally {
      setSaving(false);
    }
  };
  const total = DAYS.reduce(
    (a, d) => a + (avail[teacher.id]?.[d]?.length || 0),
    0
  );
  return (
    <Card style={{ padding: 24, marginBottom: 16 }}>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 16,
          marginBottom: 16,
          flexWrap: "wrap",
        }}
      >
        <Avatar user={teacher} size={48} />
        <div style={{ flex: 1 }}>
          <div style={{ fontWeight: 700, fontSize: 17, color: "#1B2D6B" }}>
            {teacher.name}
          </div>
          <div style={{ fontSize: 14, color: "#9CA3AF", marginTop: 2 }}>
            {total} available slots/week
          </div>
        </div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          <div
            style={{
              display: "flex",
              gap: 3,
              background: "#F3F4F6",
              borderRadius: 10,
              padding: 3,
            }}
          >
            {[
              { k: "grid", l: "Grid" },
              { k: "schedule", l: "Schedule" },
            ].map((v) => (
              <button
                key={v.k}
                onClick={() => setMode(v.k)}
                style={{
                  padding: "6px 14px",
                  borderRadius: 8,
                  border: "none",
                  cursor: "pointer",
                  fontWeight: 600,
                  fontSize: 13,
                  fontFamily: "Nunito",
                  background: mode === v.k ? "#fff" : "transparent",
                  color: mode === v.k ? "#1B2D6B" : "#6B7280",
                  boxShadow:
                    mode === v.k ? "0 1px 3px rgba(0,0,0,.08)" : "none",
                  transition: "all .15s",
                }}
              >
                {v.l}
              </button>
            ))}
          </div>
          {!readOnly &&
            !editMode &&
            (editing ? (
              <div style={{ display: "flex", gap: 8 }}>
                <Btn
                  variant="ghost"
                  size="sm"
                  onClick={() => setEditing(false)}
                >
                  {"Cancel"}
                </Btn>
                <Btn size="sm" onClick={save} disabled={saving}>
                  {saving ? "Saving..." : "Save"}
                </Btn>
              </div>
            ) : (
              <Btn variant="ghost" size="sm" onClick={openEdit}>
                Edit
              </Btn>
            ))}
        </div>
      </div>
      {mode === "schedule" ? (
        <AvailScheduleView teacher={teacher} avail={avail} />
      ) : (editing || editMode) && !readOnly ? (
        <div style={{ overflowX: "auto" }}>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "56px repeat(7,1fr)",
              gap: 3,
              minWidth: 500,
            }}
          >
            <div />
            {DAYS.map((d) => (
              <div
                key={d}
                style={{
                  textAlign: "center",
                  fontSize: 11,
                  fontWeight: 700,
                  color: "#9CA3AF",
                  padding: "4px 0",
                  textTransform: "uppercase",
                }}
              >
                {d}
              </div>
            ))}
            {ALL_TIMES.map((h) => (
              <div key={h} style={{ display: "contents" }}>
                <div
                  style={{
                    fontSize: 10,
                    color: "#D1D5DB",
                    display: "flex",
                    alignItems: "center",
                    whiteSpace: "nowrap",
                  }}
                >
                  {h}
                </div>
                {DAYS.map((d) => {
                  const on = editMode
                    ? (externalSlots?.[d] || []).includes(h)
                    : (ea[d] || []).includes(h);
                  const canClick = editMode || editing;
                  return (
                    <button
                      key={d + h}
                      onClick={() => {
                        if (canClick) toggle(d, h);
                      }}
                      style={{
                        height: 22,
                        borderRadius: 5,
                        border: "none",
                        cursor: "pointer",
                        background: on ? color + "28" : "#F9FAFB",
                        borderBottom: `3px solid ${on ? color : "transparent"}`,
                        transition: "all .1s",
                      }}
                    />
                  );
                })}
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div>
          <div style={{ display: "flex", gap: 6, marginBottom: 8 }}>
            {DAYS.map((d) => {
              const n = (avail[teacher.id]?.[d] || []).length;
              return (
                <div key={d} style={{ flex: 1, textAlign: "center" }}>
                  <div
                    style={{
                      fontSize: 10,
                      color: "#D1D5DB",
                      fontWeight: 700,
                      textTransform: "uppercase",
                      marginBottom: 4,
                    }}
                  >
                    {d[0]}
                  </div>
                  <div
                    style={{
                      height: 8,
                      borderRadius: 4,
                      background: n > 0 ? color + "55" : "#F3F4F6",
                    }}
                  />
                  <div style={{ fontSize: 10, color: "#9CA3AF", marginTop: 3 }}>
                    {n}
                  </div>
                </div>
              );
            })}
          </div>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            {DAYS.map((d) => {
              const slots = avail[teacher.id]?.[d] || [];
              return slots.length > 0 ? (
                <div key={d} style={{ fontSize: 11, color: "#6B7280" }}>
                  <b>{d}:</b> {slots.join(", ")}
                </div>
              ) : null;
            })}
          </div>
        </div>
      )}
    </Card>
  );
}

/* ── Sidebar ── */
function YallaLogo({ size = 38 }) {
  return (
    <img
      src="data:image/png;base64,"
      alt="Yalla English"
      style={{ width: size, height: size, objectFit: "contain", flexShrink: 0 }}
    />
  );
}

function NotifBell() {
  const { notifs, clear } = useInAppNotifs();
  const [open, setOpen] = useState(false);
  const unread = notifs.length;
  const ref = useRef();
  useEffect(() => {
    const close = (e) => {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", close);
    return () => document.removeEventListener("mousedown", close);
  }, []);
  return (
    <div
      ref={ref}
      style={{ position: "relative", marginLeft: "auto", zIndex: 9999 }}
    >
      <button
        onClick={() => setOpen((p) => !p)}
        style={{
          position: "relative",
          background: "none",
          border: "none",
          cursor: "pointer",
          fontSize: 20,
          padding: 4,
          borderRadius: 8,
          transition: "background .15s",
        }}
        onMouseEnter={(e) =>
          (e.currentTarget.style.background = "rgba(255,255,255,.1)")
        }
        onMouseLeave={(e) => (e.currentTarget.style.background = "none")}
      >
        🔔
        {unread > 0 && (
          <span
            style={{
              position: "absolute",
              top: 0,
              right: 0,
              background: "#EF4444",
              color: "#fff",
              borderRadius: "50%",
              width: 16,
              height: 16,
              fontSize: 10,
              fontWeight: 700,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            {unread > 9 ? "9+" : unread}
          </span>
        )}
      </button>
      {open && (
        <div
          style={{
            position: "fixed",
            top: 80,
            left: 16,
            width: 320,
            background: "#fff",
            borderRadius: 16,
            boxShadow: "0 8px 32px rgba(0,0,0,.22)",
            border: "1px solid #E5E7EB",
            zIndex: 99999,
            overflow: "hidden",
          }}
        >
          <div
            style={{
              padding: "12px 16px",
              borderBottom: "1px solid #F3F4F6",
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
            }}
          >
            <span style={{ fontWeight: 700, fontSize: 14, color: "#1B2D6B" }}>
              Notifications
            </span>
            {notifs.length > 0 && (
              <button
                onClick={() => notifs.forEach((n) => clear(n.id))}
                style={{
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  fontSize: 12,
                  color: "#9CA3AF",
                  fontWeight: 600,
                }}
              >
                Clear all
              </button>
            )}
          </div>
          <div style={{ maxHeight: 320, overflowY: "auto" }}>
            {notifs.length === 0 && (
              <div
                style={{
                  padding: "24px 16px",
                  textAlign: "center",
                  color: "#9CA3AF",
                  fontSize: 14,
                }}
              >
                No notifications
              </div>
            )}
            {notifs.map((n) => (
              <div
                key={n.id}
                style={{
                  padding: "12px 16px",
                  borderBottom: "1px solid #F9FAFB",
                  display: "flex",
                  gap: 12,
                  alignItems: "flex-start",
                }}
              >
                <span style={{ fontSize: 20, flexShrink: 0 }}>
                  {n.type === "warning"
                    ? "⚠️"
                    : n.type === "success"
                    ? "✅"
                    : "🔔"}
                </span>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div
                    style={{ fontWeight: 600, fontSize: 13, color: "#1B2D6B" }}
                  >
                    {n.title}
                  </div>
                  <div
                    style={{
                      fontSize: 12,
                      color: "#6B7280",
                      marginTop: 2,
                      lineHeight: 1.5,
                    }}
                  >
                    {n.body}
                  </div>
                </div>
                <button
                  onClick={() => clear(n.id)}
                  style={{
                    background: "none",
                    border: "none",
                    cursor: "pointer",
                    color: "#D1D5DB",
                    fontSize: 16,
                    flexShrink: 0,
                    lineHeight: 1,
                  }}
                >
                  ✕
                </button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

