/* ═══ NOTIFICATION SYSTEM ═══ */

// Request push notification permission
async function requestNotifPermission() {
  if (!("Notification" in window)) return false;
  if (Notification.permission === "granted") return true;
  if (Notification.permission === "denied") return false;
  const result = await Notification.requestPermission();
  return result === "granted";
}

// Send a push notification
function sendPushNotif(title, body, icon = "") {
  if (Notification.permission !== "granted") return;
  const n = new Notification(title, {
    body,
    icon,
    badge: icon,
    vibrate: [200, 100, 200],
  });
  setTimeout(() => n.close(), 8000);
  return n;
}

// Ring alarm sound using Web Audio API
function createAlarmSound() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const playBeep = (freq, start, dur) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.frequency.value = freq;
      osc.type = "sine";
      gain.gain.setValueAtTime(0, ctx.currentTime + start);
      gain.gain.linearRampToValueAtTime(0.4, ctx.currentTime + start + 0.05);
      gain.gain.linearRampToValueAtTime(0, ctx.currentTime + start + dur);
      osc.start(ctx.currentTime + start);
      osc.stop(ctx.currentTime + start + dur + 0.1);
    };
    // Ring pattern: 3 beeps, repeat
    const ring = () => {
      playBeep(880, 0, 0.15);
      playBeep(880, 0.2, 0.15);
      playBeep(1100, 0.4, 0.25);
    };
    ring();
    return { ring, ctx };
  } catch (e) {
    return null;
  }
}

// Class alarm modal component
function ClassAlarmModal({ cls, teacher, student, onClose }) {
  const [ringing, setRinging] = useState(true);
  const alarmRef = useRef(null);
  const intervalRef = useRef(null);

  useEffect(() => {
    // Start ringing immediately and every 4 seconds
    const sound = createAlarmSound();
    alarmRef.current = sound;
    if (sound) {
      intervalRef.current = setInterval(() => {
        if (ringing) sound.ring();
      }, 4000);
    }
    // Push notification too
    sendPushNotif(
      "Class starting in 1 minute!",
      `${student?.name} - ${cls.time} (${cls.duration || 55} min)`
    );
    return () => {
      clearInterval(intervalRef.current);
      try {
        alarmRef.current?.ctx?.close();
      } catch (e) {}
    };
  }, []);

  const dismiss = () => {
    setRinging(false);
    clearInterval(intervalRef.current);
    try {
      alarmRef.current?.ctx?.close();
    } catch (e) {}
    onClose();
  };

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 9999,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "rgba(0,0,0,.7)",
        backdropFilter: "blur(4px)",
      }}
    >
      <div
        className="scale-in"
        style={{
          background: "#fff",
          borderRadius: 24,
          padding: "40px 48px",
          maxWidth: 420,
          width: "90%",
          textAlign: "center",
          boxShadow: "0 32px 80px rgba(0,0,0,.4)",
        }}
      >
        {/* Pulsing bell */}
        <div
          style={{
            fontSize: 64,
            animation: "pulse 0.5s ease-in-out infinite",
            marginBottom: 16,
          }}
        >
          🔔
        </div>
        <div
          style={{
            fontFamily: "Poppins,sans-serif",
            fontWeight: 800,
            fontSize: 26,
            color: "#1B2D6B",
            marginBottom: 8,
          }}
        >
          Class in 1 minute!
        </div>
        <div style={{ fontSize: 16, color: "#6B7280", marginBottom: 6 }}>
          {student?.name}
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 12,
            marginBottom: 24,
          }}
        >
          <span
            style={{
              fontFamily: "Poppins,sans-serif",
              fontSize: 36,
              fontWeight: 700,
              color: "#22C55E",
            }}
          >
            {cls.time}
          </span>
          <div style={{ textAlign: "left" }}>
            <div style={{ fontSize: 13, color: "#9CA3AF" }}>Duration</div>
            <div style={{ fontWeight: 700, color: "#1B2D6B" }}>
              {cls.duration || 55} min
            </div>
          </div>
        </div>
        <button
          onClick={dismiss}
          style={{
            width: "100%",
            padding: "14px",
            borderRadius: 12,
            border: "none",
            background: "#1B2D6B",
            color: "#fff",
            fontFamily: "Poppins,sans-serif",
            fontWeight: 700,
            fontSize: 16,
            cursor: "pointer",
            transition: "all .18s",
          }}
          onMouseEnter={(e) => (e.currentTarget.style.background = "#0f1e4d")}
          onMouseLeave={(e) => (e.currentTarget.style.background = "#1B2D6B")}
        >
          OK, I'm ready!
        </button>
      </div>
    </div>
  );
}

// In-app notification bell state
let _inAppNotifs = [];
let _notifListeners = [];
function addInAppNotif(notif) {
  _inAppNotifs = [{ id: Date.now(), ...notif }, ..._inAppNotifs].slice(0, 20);
  _notifListeners.forEach((cb) => cb([..._inAppNotifs]));
}
function useInAppNotifs() {
  const [notifs, setNotifs] = useState([..._inAppNotifs]);
  useEffect(() => {
    const cb = (n) => setNotifs(n);
    _notifListeners.push(cb);
    return () => {
      _notifListeners = _notifListeners.filter((x) => x !== cb);
    };
  }, []);
  return {
    notifs,
    clear: (id) => {
      _inAppNotifs = _inAppNotifs.filter((n) => n.id !== id);
      _notifListeners.forEach((cb) => cb([..._inAppNotifs]));
    },
  };
}

// Send notification - tries push first, falls back to in-app
function notify(title, body, type = "info") {
  // In-app always
  addInAppNotif({ title, body, type });
  // Push if permitted
  if (Notification.permission === "granted") {
    try {
      const n = new Notification(title, { body, icon: "", badge: "" });
      setTimeout(() => n.close(), 8000);
    } catch (e) {}
  }
}

// Notification manager hook - used in teacher view
function useClassNotifications(user, classes, students) {
  const [alarm, setAlarm] = useState(null);
  const scheduledRef = useRef(new Set());

  useEffect(() => {
    if (!user || user.role !== "teacher") return;
    requestNotifPermission();
  }, [user?.id]);

  useEffect(() => {
    if (!user || user.role !== "teacher" || !classes.length) return;
    const myClasses = classes.filter(
      (c) => c.teacherId === user.id && c.status === "scheduled"
    );

    myClasses.forEach((c) => {
      const ms = msUntil(c.date, c.time);
      if (ms <= 0 || ms > 24 * 60 * 60 * 1000) return;
      const s = students.find((st) => st.id === c.studentId);
      const name = s?.name || "Student";

      // 5-min notification
      const key5 = `n5_${c.id}`;
      const ms5 = ms - 5 * 60 * 1000;
      if (ms5 > 0 && !scheduledRef.current.has(key5)) {
        scheduledRef.current.add(key5);
        setTimeout(
          () => notify("Class in 5 minutes", `${name} at ${c.time}`, "warning"),
          ms5
        );
      } else if (ms5 <= 0 && ms > 0 && !scheduledRef.current.has(key5)) {
        // Between 1-5 min: notify now
        scheduledRef.current.add(key5);
        notify(
          "Class starting soon",
          `${name} at ${c.time} in less than 5 minutes`,
          "warning"
        );
      }

      // 1-min alarm
      const key1 = `n1_${c.id}`;
      const ms1 = ms - 60 * 1000;
      if (ms1 > 0 && !scheduledRef.current.has(key1)) {
        scheduledRef.current.add(key1);
        setTimeout(() => setAlarm({ cls: c, student: s }), ms1);
      } else if (ms1 <= 0 && ms > 0 && !scheduledRef.current.has(key1)) {
        scheduledRef.current.add(key1);
        setAlarm({ cls: c, student: s });
      }
    });
  }, [classes]);

  return { alarm, clearAlarm: () => setAlarm(null) };
}

