    await sbUpsert(
      "messages",
      m.id ? { ...row, id: m.id } : row,
      "class_id,type"
    );
    await sbPatch("classes", `id=eq.${m.classId}`, { status: "completed" });
    await loadAll();
    toast("Feedback saved ✓");
